import CoreMotion
import SwiftUI

class MotionManager: ObservableObject {
    private let manager = CMMotionManager()
    @Published var repCount = 0
    @Published var isTracking = false
    @Published var isAvailable: Bool

    private var filtered: Double = 0
    private let alpha = 0.15
    private var lastRepTime: Date = .distantPast
    private let cooldown: TimeInterval = 0.5
    private let threshold: Double = 0.4

    init() {
        isAvailable = manager.isDeviceMotionAvailable
    }

    func startTracking() {
        guard isAvailable else { return }
        repCount = 0
        filtered = 0
        isTracking = true
        manager.deviceMotionUpdateInterval = 1.0 / 60.0
        manager.startDeviceMotionUpdates(to: OperationQueue()) { [weak self] motion, _ in
            guard let self, let motion else { return }
            let raw = motion.userAcceleration.y
            self.filtered = self.alpha * raw + (1 - self.alpha) * self.filtered
            let now = Date()
            if self.filtered > self.threshold && now.timeIntervalSince(self.lastRepTime) > self.cooldown {
                self.lastRepTime = now
                DispatchQueue.main.async { self.repCount += 1 }
            }
        }
    }

    func stopTracking() {
        manager.stopDeviceMotionUpdates()
        isTracking = false
    }

    deinit {
        manager.stopDeviceMotionUpdates()
    }
}
